import sqlite3def populate_inventory_and_link():    conn = sqlite3.connect("skypix_config.db")    cursor = conn.cursor()    # 1. Add the Primes (The Inventory)    cursor.execute("INSERT INTO camera_kit (friendly_name, pixel_width_um) VALUES ('ASI2600MC', 3.76)")    cam_id = cursor.lastrowid        cursor.execute("INSERT INTO filter_kit (friendly_name, band) VALUES ('Antlia Alp-T', 'ha')")    f_id = cursor.lastrowid    # 2. The Link (The 'GAS Planning Sheet' equivalent)    # This is where we 'bolt' them to Rig #1    cursor.execute("INSERT INTO rig_camera_eligibility (rig_id, camera_id) VALUES (1, ?)", (cam_id,))    cursor.execute("INSERT INTO rig_filter_eligibility (rig_id, filter_id) VALUES (1, ?)", (f_id,))    conn.commit()    conn.close()    print(f"✓ Inventory added and linked to Rig 1.")if __name__ == "__main__":    populate_inventory_and_link()